<template>
    <VaForm ref="form" @submit.prevent="submit">
        <h1 class="font-semibold text-4xl mb-4">Sign up</h1>
        <p class="text-base mb-4 leading-5">
            Have an account?
            <RouterLink :to="{ name: 'login' }" class="font-semibold text-primary">Login</RouterLink>
        </p>
        <VaInput
            v-model="formData.email"
            :rules="[
                (v: string) => !!v || 'Email field is required',
                (v: string) => /.+@.+\..+/.test(v) || 'Email should be valid',
            ]"
            class="mb-4"
            label="Email"
            type="email"
        />
        <VaValue v-slot="isPasswordVisible" :default-value="false">
            <VaInput
                ref="password1"
                v-model="formData.password"
                :rules="passwordRules"
                :type="isPasswordVisible.value ? 'text' : 'password'"
                class="mb-4"
                label="Password"
                messages="Password must be at least 6 characters."
                @clickAppendInner.stop="isPasswordVisible.value = !isPasswordVisible.value"
            >
                <template #appendInner>
                    <VaIcon
                        :name="isPasswordVisible.value ? 'mso-visibility_off' : 'mso-visibility'"
                        class="cursor-pointer"
                        color="secondary"
                    />
                </template>
            </VaInput>
            <VaInput
                ref="password2"
                v-model="formData.repeatPassword"
                :rules="[
                    (v: string) => !!v || 'Repeat Password field is required',
                    (v: string) => v === formData.password || 'Passwords don\'t match',
                ]"
                :type="isPasswordVisible.value ? 'text' : 'password'"
                class="mb-4"
                label="Repeat Password"
                @clickAppendInner.stop="isPasswordVisible.value = !isPasswordVisible.value"
            >
                <template #appendInner>
                    <VaIcon
                        :name="isPasswordVisible.value ? 'mso-visibility_off' : 'mso-visibility'"
                        class="cursor-pointer"
                        color="secondary"
                    />
                </template>
            </VaInput>
        </VaValue>

        <div class="flex justify-center mt-4">
            <VaButton class="w-full" @click="submit"> Create account</VaButton>
        </div>
    </VaForm>
</template>

<script lang="ts" setup>
import { reactive } from 'vue'
import { useRouter } from 'vue-router'
import { useForm, useToast } from 'vuestic-ui'
import useFirebase from '../../composables/useFirebase'
import api from '../../services/api'
import { usePublicStore } from '../../stores/public-store'
import { useUserStore } from '../../stores/user-store'

const { validate } = useForm('form')
const { push } = useRouter()
const { init } = useToast()
const { firebaseSignup } = useFirebase()
const publicStore = usePublicStore()
const userStore = useUserStore()

const formData = reactive({
    email: '',
    password: '',
    repeatPassword: '',
})

const submit = async () => {
    if (validate()) {
        try {
            const { accessToken } = await firebaseSignup(formData.email, formData.password)
            api.setAuthToken(accessToken)
            const { data } = await api.login()
            userStore.setUserProfile(data.data)
            await publicStore.doAfterLogin()
        } catch (error) {
            console.error('Signup failed:', error)
            init({ message: 'Sign up failed. Please try again.', color: 'danger' })
            return
        }

        init({
            message: "You've successfully signed up",
            color: 'success',
        })
        push({ name: 'dashboard' })
    }
}

const passwordRules: ((v: string) => boolean | string)[] = [
    (v) => !!v || 'Password field is required',
    (v) => (v && v.length >= 6) || 'Password must be at least 6 characters long',
]
</script>
